      "id": "AC-6",
      "given": "A patient has an appointment starting in 1 hour",
      "when": "The patient requests cancellation",
      "then": "The cancellation is rejected with an error indicating the cancellation window has closed"
    },
    {
      "id": "AC-7",
      "given": "A patient has an appointment starting in 30 minutes",
      "when": "A staff administrator requests cancellation of that appointment",
      "then": "The appointment is cancelled successfully"
    },
    {
